import React, { type ComponentProps, Suspense, lazy } from 'react'
import { Button, useOverlay, DataBlock } from '@fs/zion-ui'
import type { ConclusionType } from '@fs/zion-tree-types'
import { type Issue } from '@fs/zion-person-quality-score-issues'
import { ContentAdd } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import Conclusion from './Conclusion'
import Label from './Label'
import { getConclusionDisplayLabel, livingDeathConclusion } from '../helpers/helpers'

const ConclusionDialog = lazy(() => import('./overlays/ConclusionDialog'))

type Props = Partial<ComponentProps<typeof ConclusionDialog> & ComponentProps<typeof Conclusion>> & {
  /** The conclusion type to be added, if the conclusion doesn't exist. */
  type: ConclusionType

  /** If true, the conclusion can be added (if the person doesn't have it), but it cannot be edited after. */
  disallowEdit?: boolean

  /** Minimum height of dialog */
  minHeight?: number

  /** Maximum height of dialog */
  maxHeight?: number

  /** Issues associated to the conclusion */
  issues?: Issue[]
}

/**
 * If a conclusion is not provided, the conclusion label for the specified type is still displayed
 * and an "+ ADD" button is displayed to allow the user to add the specified conclusion.
 */
export default function ConclusionWithAdd({
  type,
  disallowEdit,
  headingLevel,
  autoOpen,
  minHeight,
  maxHeight,
  issues,
  ...props
}: Props): JSX.Element {
  const [t] = useTranslation()
  const overlay = useOverlay({ initiallyOpen: autoOpen })

  const { conclusion, person, readOnly, relationshipId, simple } = props

  // We don't include disallowEdit here, since we want the Add button to still be enabled when disallowEdit is true.
  const isReadOnly = readOnly || person?.readOnly || person?.deleted

  const conclusionDisplayName = getConclusionDisplayLabel(t, type)
  return conclusion || type === 'DEATH' ? (
    <Conclusion
      readOnly={isReadOnly || disallowEdit}
      headingLevel={headingLevel}
      autoOpen={autoOpen}
      {...props}
      conclusion={conclusion || livingDeathConclusion}
      issues={issues}
    />
  ) : (
    <DataBlock
      as={headingLevel}
      heading={<Label conclusionType={type} />}
      data={
        <>
          <Button
            Icon={ContentAdd}
            disabled={isReadOnly}
            onClick={overlay.handleClick}
            data-testid="conclusion:add:button"
            aria-label={t('conclusion.add.aria-label', { conclusion: conclusionDisplayName })}
          >
            {t('conclusion.add.button')}
          </Button>

          <Suspense fallback="">
            {(overlay.isOpen || overlay.transitioning) && (
              <ConclusionDialog
                type={type}
                overlay={overlay}
                readOnly={isReadOnly}
                relationshipId={relationshipId}
                mode="add"
                simple={simple}
                minHeight={minHeight}
                maxHeight={maxHeight}
                {...props}
              />
            )}
          </Suspense>
        </>
      }
    />
  )
}
