import React from 'react'
import { useTranslation } from 'react-i18next'
import { ContentAdd } from '@fs/zion-icon'
import { useOverlay, Button } from '@fs/zion-ui'
import type { Person, NonVitalEventType, NonVitalFactType } from '@fs/zion-tree-types'
import AddConclusionMenuOverlay from './AddConclusionMenuOverlay'

type BaseAddConclusionMenuButtonProps = {
  /** Person object for who this conclusion will be added to. */
  person: Person
}

type AddConclusionMenuButtonPropsEvent = BaseAddConclusionMenuButtonProps & {
  /** Category of conclusion being added. */
  conclusionCategory: 'otherEvent'

  /** Types of conclusions to hide from the dropdown menu. */
  conclusionTypesToHide?: NonVitalEventType[]

  /** Types of conclusions to disable from the dropdown menu. */
  conclusionTypesToDisable?: NonVitalEventType[]
}

type AddConclusionMenuButtonPropsFact = BaseAddConclusionMenuButtonProps & {
  /** Category of conclusion being added. */
  conclusionCategory: 'otherFact'

  /** Types of conclusions to hide from the dropdown menu. */
  conclusionTypesToHide?: NonVitalFactType[]

  /** Types of conclusions to disable from the dropdown menu. */
  conclusionTypesToDisable?: NonVitalFactType[]
}

type AddConclusionMenuButtonProps = AddConclusionMenuButtonPropsEvent | AddConclusionMenuButtonPropsFact

function AddConclusionMenuButton(props: AddConclusionMenuButtonPropsEvent): JSX.Element | null
function AddConclusionMenuButton(props: AddConclusionMenuButtonPropsFact): JSX.Element | null
function AddConclusionMenuButton({
  conclusionCategory,
  person,
  conclusionTypesToHide,
  conclusionTypesToDisable,
}: AddConclusionMenuButtonProps): JSX.Element | null {
  const menuOverlay = useOverlay()
  const [t] = useTranslation()

  if (!person) return null

  return (
    <>
      <Button
        disabled={person.readOnly || person.deleted}
        data-testid={`add-new-${conclusionCategory}-button`}
        Icon={ContentAdd}
        onClick={menuOverlay.handleClick}
      >
        {t(
          conclusionCategory === 'otherEvent'
            ? 'add-new-conclusion-button.add-otherEvent'
            : 'add-new-conclusion-button.add-otherFact'
        )}
      </Button>

      {conclusionCategory === 'otherEvent' ? (
        <AddConclusionMenuOverlay
          person={person}
          menuOverlay={menuOverlay}
          conclusionCategory="otherEvent"
          conclusionTypesToHide={conclusionTypesToHide}
          conclusionTypesToDisable={conclusionTypesToDisable}
          inline={false}
        />
      ) : (
        <AddConclusionMenuOverlay
          person={person}
          menuOverlay={menuOverlay}
          conclusionCategory="otherFact"
          conclusionTypesToHide={conclusionTypesToHide}
          conclusionTypesToDisable={conclusionTypesToDisable}
          inline={false}
        />
      )}
    </>
  )
}

export default AddConclusionMenuButton
