const SideSheetDivider = (): JSX.Element => <Divider marginY="xs" />

const genderColors = {
  MALE: 'blue',
  FEMALE: 'red',
  UNKNOWN: 'gray',
} as const

type CheckHeadingProps = {
  ref: MutableRefObject<HTMLDivElement | null>
  headingRef: MutableRefObject<HTMLSpanElement | null>
  showHeadingRef: MutableRefObject<boolean>
  cb: Dispatch<SetStateAction<boolean>>
}

const checkHeading = ({ ref, headingRef, showHeadingRef, cb }: CheckHeadingProps): number | null => {
  if (!ref.current || !headingRef.current) return null

  const nameRect = ref.current.getBoundingClientRect()
  const headerRect = headingRef.current.getBoundingClientRect()

  // Add a margin to avoid flickering when scrolling slowly past the transition point
  // Set the transition point to make the name visible on the heading right after scrolling down past the name
  const transitionPoint = nameRect.y / 4
  const margin = Math.max(2, Math.round(headerRect.height * 0.08))
  const showAt = headerRect.bottom - margin
  const hideAt = headerRect.bottom + margin

  if (!showHeadingRef.current && transitionPoint <= showAt && headerRect.bottom > nameRect.top) cb(true)
  else if (showHeadingRef.current && nameRect.top >= hideAt) cb(false)

  return transitionPoint
}

type SheetPanelProps = {
  cjk?: boolean
  displayPerson: UnknownPerson | TdPerson | LoadingPerson<Partial<TdPerson>>
  showFamilyMembersNotFacts?: boolean
  readOnlyMode?: boolean
  headingRef: MutableRefObject<HTMLSpanElement | null>
  showHeadingRef: MutableRefObject<boolean>
  setShowHeading: Dispatch<SetStateAction<boolean>>
  linksOpenNewTab?: boolean
  showPQSTag?: boolean
}

function SheetPanel({
  cjk: isCjk,
  displayPerson,
  showFamilyMembersNotFacts,
  readOnlyMode,
  headingRef,
  showHeadingRef,
  setShowHeading,
  linksOpenNewTab,
  showPQSTag = false,
}: SheetPanelProps): JSX.Element {
  const personHeadingRef = useRef<HTMLDivElement>(null)

  const altNameOverlay = useOverlay()

  const [t] = useTranslation()

  useAnimationFrames(() => checkHeading({ ref: personHeadingRef, headingRef, showHeadingRef, cb: setShowHeading }))

  const newTabProps = linksOpenNewTab ? { target: '_blank', rel: 'noopener noreferrer' } : {}

  const { name, id } = displayPerson ?? {}
  const { lifeSketch, otherConclusions, birth, christening, death, burial } =
    displayPerson && !isUnknownPerson(displayPerson) ? displayPerson : {}

  const { isOn: addAlternateName } = useFeatureFlag('ginkgo_personSheet_addAlternateName')

  const altNameConclusions = otherConclusions?.filter((conclusion) => conclusion.type === 'ALTERNATE_NAME')
  const eventConclusions = otherConclusions?.filter(
    (conclusion) => getConclusionCategory(conclusion.type) === 'otherEvent'
  )
  const eventCount = eventConclusions ? eventConclusions?.length : 0
  const factConclusions = otherConclusions?.filter((conclusion) => {
    if (addAlternateName && conclusion.type === 'ALTERNATE_NAME') return false
    return getConclusionCategory(conclusion.type) === 'otherFact'
  })
  const factCount = factConclusions ? factConclusions?.length : 0

  useSubscribe({ evt: events.conclusion }, () => {
    if (id && id !== 'UNKNOWN') updatePersonObject(id)
  })

  return (
    <>
      <PersonOverlaySheetSummary
        cjk={isCjk}
        readOnlyMode={readOnlyMode}
        personHeadingRef={personHeadingRef}
        displayPerson={displayPerson}
        newTabProps={newTabProps}
        showPQSTag={showPQSTag}
      />

      {name && !isLoadingPerson(displayPerson) && !isUnavailablePerson(displayPerson) && (
        <>
          <Separator size="xs" />
          <Grid guttersY="nano">
            <H3 size="H5" supplementary>
              {t('person.person-sheet.vitals')}
            </H3>
            <ConclusionWithAdd
              type="BIRTH"
              showSourceCount
              disableOverlay
              person={displayPerson as CardPerson}
              conclusion={birth}
              readOnly={readOnlyMode}
            />
            <ConclusionWithAdd
              type="CHRISTENING"
              showSourceCount
              disableOverlay
              person={displayPerson as CardPerson}
              conclusion={christening}
              readOnly={readOnlyMode}
            />
            <ConclusionWithAdd
              type="DEATH"
              showSourceCount
              disableOverlay
              person={displayPerson as CardPerson}
              conclusion={death}
              readOnly={readOnlyMode}
            />
            <ConclusionWithAdd
              type="BURIAL"
              showSourceCount
              disableOverlay
              person={displayPerson as CardPerson}
              conclusion={burial}
              readOnly={readOnlyMode}
            />
          </Grid>

          {!showFamilyMembersNotFacts && (
            <>
              <SideSheetDivider />
              {addAlternateName && (
                <>
                  <Grid guttersY="nano">
                    <Cell>
                      <H3 size="H5" supplementary>
                        <Ellipsis>{t('person.person-sheet.alternate-names')}</Ellipsis>
                      </H3>
                      {!readOnlyMode && (
                        <>
                          <Button
                            onClick={altNameOverlay.handleClick}
                            Icon={ContentAdd}
                            disabled={displayPerson.readOnly || displayPerson.deleted}
                            {...newTabProps}
                          >
                            {t('person.person-sheet.add-alternate-name')}
                          </Button>
                          {(altNameOverlay.isOpen || altNameOverlay.transitioning) && (
                            <AddConclusionDialog
                              overlay={altNameOverlay}
                              conclusionType="ALTERNATE_NAME"
                              person={displayPerson as CardPerson}
                            />
                          )}
                        </>
                      )}
                    </Cell>

                    {altNameConclusions?.map((conclusion) => {
                      return (
                        <Conclusion
                          key={conclusion.id}
                          showSourceCount
                          disableOverlay
                          person={displayPerson as CardPerson}
                          conclusion={conclusion}
                          truncate
                        />
                      )
                    })}
                  </Grid>

                  <SideSheetDivider />
                </>
              )}

              <Grid guttersY="nano">
                <Cell>
                  <H3 size="H5" supplementary>
                    <Ellipsis>
                      {t('person.person-sheet.events')} ({eventCount})
                    </Ellipsis>
                  </H3>

                  {!readOnlyMode && (
                    <AddConclusionMenuButton
                      conclusionCategory="otherEvent"
                      person={displayPerson as CardPerson}
                      data-testid="addEventPersonSheet"
                      conclusionTypesToDisable={
                        displayPerson.living ? ['BAR_MITZVAH', 'BAS_MITZVAH', 'RELIGIOUS_AFFILIATION'] : undefined
                      }
                    />
                  )}
                </Cell>

                {eventConclusions?.map((conclusion) => {
                  return (
                    <Conclusion
                      key={conclusion.id}
                      showSourceCount
                      disableOverlay
                      person={displayPerson as CardPerson}
                      conclusion={conclusion}
                      truncate
                    />
                  )
                })}
              </Grid>

              <SideSheetDivider />

              <Grid guttersY="nano">
                <Cell>
                  <H3 size="H5" supplementary>
                    <Ellipsis>
                      {t('person.person-sheet.facts')} ({factCount})
                    </Ellipsis>
                  </H3>
                  {!readOnlyMode && (
                    <AddConclusionMenuButton
                      conclusionCategory="otherFact"
                      person={displayPerson as CardPerson}
                      conclusionTypesToHide={addAlternateName ? ['ALTERNATE_NAME'] : []}
                      data-testid="addFactPersonSheet"
                      conclusionTypesToDisable={
                        displayPerson.living ? ['RACE', 'TRIBE_NAME', 'NATIONAL_ID'] : undefined
                      }
                    />
                  )}
                </Cell>

                {factConclusions?.map((conclusion) => {
                  return (
                    <Conclusion
                      key={conclusion.id}
                      showSourceCount
                      disableOverlay
                      person={displayPerson as CardPerson}
                      conclusion={conclusion}
                      truncate
                    />
                  )
                })}
              </Grid>

              <SideSheetDivider />

              {name && (
                <Lifesketch
                  headingLevel="h3"
                  // @ts-expect-error - This is a bit of a hack to get around the fact that Lifesketch requires a conclusion of type LIFE_SKETCH, but we want to allow passing in a full person object that may not have that conclusion. We want to avoid making the conclusion optional because that would make the types less accurate for cases where we do have a life sketch conclusion.
                  conclusion={lifeSketch || (!readOnlyMode ? { type: 'LIFE_SKETCH' } : {})}
                  person={displayPerson as CardPerson}
                  readOnly
                />
              )}
            </>
          )}
          {showFamilyMembersNotFacts && (
            <>
              <SideSheetDivider />
              <H3 size="H5" supplementary>
                <Ellipsis>{t('person.person-sheet.relationships')}</Ellipsis>
              </H3>
              <Separator size="xxs" />
              <FamilyMembers displayPerson={displayPerson} personObj={displayPerson} />
            </>
          )}
        </>
      )}
    </>
  )
}

type UseInfoSheetReturn = ReturnType<typeof useInfoSheet>

type PersonSheetProps = {
  /** PID to display inside the sheet */
  personId: PID
  /** Result of zion-ui's useInfoSheet hook */
  sheet: UseInfoSheetReturn
  /** When 'true', does not allow person data to be added from the sidesheet */
  readOnlyMode?: boolean
  /** Props spread onto the personsheet's infosheet */
  infoSheetProps?: Omit<
    React.ComponentProps<typeof InfoSheet>,
    'size' | keyof UseInfoSheetReturn | 'headingColor' | 'title'
  >
  /** Size of the info sheet */
  sheetSize?: 'sm' | 'md' | 'lg'
  /** CJK flag for name display */
  cjk?: boolean
  /** Show family members instead of facts */
  showFamilyMembersNotFacts?: boolean
  /** Open links in new tab */
  linksOpenNewTab?: boolean
  /** Show PQS tag */
  showPQSTag?: boolean
}

/**
 * Person Sheet component for displaying detailed person information in a side sheet
 */
function PersonSheet({
  personId,
  sheet,
  readOnlyMode,
  infoSheetProps = {},
  sheetSize = 'md',
  ...rest
}: PersonSheetProps): JSX.Element {
  const activePersonId = personId || undefined
  const headingRef = useRef<HTMLSpanElement>(null)
  const showHeadingRef = useRef<boolean>(false)
  const [showHeading, setShowHeading] = useState<boolean>(false)
  // Hack to only fetch when needed since InfoSheet will not let you conditionally render it.
  // If you change this, but infosheet is still dumb and someone uses the openPersonSheet prop,
  // calls will happen prematurely and pedigrees will be a nightmare
  const idOrUndefined = sheet.isOpen || sheet.transitioning ? activePersonId : undefined
  const placeholderPerson: Partial<TdPerson> = { id: personId }
  const displayPerson = usePerson(idOrUndefined, 'full', placeholderPerson)

  // We're doing this because if we rely on react state inside useAnimationFrames, it can get stale and trigger unnecessary setState calls.
  // We need both the state and the ref, so that the heading re-renders when needed (via state) and so that the useAnimationFrames cb doesn't call setState unnecessarily.
  // Yes, we know that react will no-op if you're setting new state identical to previous, but we want to be more efficient.
  showHeadingRef.current = showHeading

  return (
    <InfoSheet
      data-testid="personSheet"
      {...infoSheetProps}
      size={sheetSize}
      {...sheet}
      headingColor={displayPerson.gender ? genderColors[displayPerson.gender] : genderColors.UNKNOWN}
      // @ts-expect-error - InfoSheet title can be a string or a ReactNode, but the types don't allow for ReactNode. Cast to any to get around this until we can update the types in zion-ui
      title={<span ref={headingRef}>{showHeading && displayPerson.name}</span>}
    >
      {(sheet.isOpen || sheet.transitioning) && (
        <SheetPanel
          displayPerson={displayPerson}
          readOnlyMode={readOnlyMode}
          headingRef={headingRef}
          showHeadingRef={showHeadingRef}
          setShowHeading={setShowHeading}
          {...rest}
        />
      )}
    </InfoSheet>
  )
}

export default memo(PersonSheet)

