import React, { type ComponentType, lazy, Suspense } from 'react'
import { useTranslation } from 'react-i18next'
import { ContentAdd } from '@fs/zion-icon'
import { Button, useOverlay } from '@fs/zion-ui'
import { GenericHeading } from '@fs/zion-ui/quarks-authorized-use-only'
import type { AttributionProps, LifeSketchConclusion, Person } from '@fs/zion-tree-types'
import RenderTheSketch from './RenderTheSketch'
import Label from './Label'

const ConclusionDialog = lazy(() => import('./overlays/ConclusionDialog'))

type LifesketchProps = {
  /** The lifesketch conclusion object, if it already exists. */
  conclusion?: LifeSketchConclusion

  /** Person object this lifesketch is for. */
  person: Person

  /** Attribution component */
  AttributionComponent?: ComponentType<AttributionProps>

  /** If true, it cannot be edited. The user can still open the dialog to see the full lifesketch and additional details. */
  readOnly?: boolean

  /** If true, the label will not be displayed. */
  hideLabel?: boolean

  /** Element to use for the label. */
  headingLevel?: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'div'

  /** Minimum height of dialog */
  minHeight?: number

  /** Maximum height of dialog */
  maxHeight?: number
}

export default function Lifesketch({
  conclusion,
  person,
  AttributionComponent,
  headingLevel = 'h5',
  readOnly,
  hideLabel,
  minHeight,
  maxHeight,
}: LifesketchProps): JSX.Element | null {
  const [t] = useTranslation()

  const conclusionDetailOverlay = useOverlay()

  if (conclusion && conclusion.type !== 'LIFE_SKETCH') {
    return null
  }

  const disabled = person?.readOnly || person?.deleted

  return (
    <>
      {!hideLabel && (
        <GenericHeading size="H6" as={headingLevel}>
          <Label conclusionType="LIFE_SKETCH" />
        </GenericHeading>
      )}
      {conclusion?.id ? (
        <>
          <RenderTheSketch preview lifesketch={conclusion} />
          <Button data-testid="lifesketch-more-button" onClick={conclusionDetailOverlay.handleClick}>
            {t('conclusion.LIFE_SKETCH.more')}
          </Button>
        </>
      ) : (
        <Button
          disabled={disabled}
          Icon={ContentAdd}
          data-testid="add-conclusion-button"
          onClick={conclusionDetailOverlay.handleClick}
        >
          {t('conclusion.LIFE_SKETCH.add.aria-label')}
        </Button>
      )}
      <Suspense fallback="">
        {(conclusionDetailOverlay.isOpen || conclusionDetailOverlay.transitioning) && (
          <ConclusionDialog
            overlay={conclusionDetailOverlay}
            conclusion={conclusion}
            person={person}
            type="LIFE_SKETCH"
            mode={!conclusion?.id ? 'add' : 'view'}
            readOnly={readOnly || disabled}
            minHeight={minHeight}
            maxHeight={maxHeight}
            AttributionComponent={AttributionComponent}
          />
        )}
      </Suspense>
    </>
  )
}
