import type { UIEvent } from 'react'
import React, { useState, lazy, Suspense } from 'react'
import { useTranslation } from 'react-i18next'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import { ListItem, useOverlay, MenuOverlay } from '@fs/zion-ui'
import { trackEvent } from '@fs/zion-analytics'
import type { Person, NonVitalEventType, NonVitalFactType } from '@fs/zion-tree-types'
import { CONCLUSION_PROPERTIES_MAP } from '../helpers/maps'
import { OTHER_EVENT_TYPES, OTHER_FACT_TYPES, getConclusionDisplayLabel } from '../helpers/helpers'

const ConclusionDialog = lazy(() => import('./overlays/ConclusionDialog'))

function getConclusionList(category: 'otherEvent', typesToHide?: NonVitalEventType[]): NonVitalEventType[]
function getConclusionList(category: 'otherFact', typesToHide?: NonVitalFactType[]): NonVitalFactType[]
function getConclusionList(
  category: 'otherEvent' | 'otherFact',
  typesToHide?: (NonVitalEventType | NonVitalFactType)[]
): (NonVitalEventType | NonVitalFactType)[] {
  const types = category === 'otherEvent' ? OTHER_EVENT_TYPES : OTHER_FACT_TYPES
  return types.filter((type) => !typesToHide?.includes(type))
}

function isTypeDisabled<T extends NonVitalEventType | NonVitalFactType>(
  type: T,
  typesToDisable: T[] | undefined
): boolean {
  return typesToDisable?.includes(type) ?? false
}

type BaseAddConclusionMenuOverlayProps = {
  /** Person object for who this conclusion will be added to. */
  person: Person

  menuOverlay: UseOverlayReturnOptions

  /** @deprecated Minimum height of dialog */
  minHeight?: number

  /** @deprecated Maximum height of dialog */
  maxHeight?: number
} & { inline?: boolean } // MenuOverlayProp

type AddConclusionMenuOverlayPropsEvent = BaseAddConclusionMenuOverlayProps & {
  /** Category of conclusion being added. */
  conclusionCategory: 'otherEvent'

  /** Types of conclusions to hide from the dropdown menu. */
  conclusionTypesToHide?: NonVitalEventType[]

  /** Types of conclusions to disable from the dropdown menu. */
  conclusionTypesToDisable?: NonVitalEventType[]
}

type AddConclusionMenuOverlayPropsFact = BaseAddConclusionMenuOverlayProps & {
  /** Category of conclusion being added. */
  conclusionCategory: 'otherFact'

  /** Types of conclusions to hide from the dropdown menu. */
  conclusionTypesToHide?: NonVitalFactType[]

  /** Types of conclusions to disable from the dropdown menu. */
  conclusionTypesToDisable?: NonVitalFactType[]
}

type AddConclusionMenuOverlayProps = AddConclusionMenuOverlayPropsEvent | AddConclusionMenuOverlayPropsFact

export default function AddConclusionMenuOverlay({
  conclusionCategory,
  person,
  conclusionTypesToHide,
  conclusionTypesToDisable,
  menuOverlay,
  ...menuOverlayProps
}: AddConclusionMenuOverlayProps): JSX.Element | null {
  const conclusionOverlay = useOverlay()
  const [t] = useTranslation()

  const [conclusionTypeToAdd, setConclusionTypeToAdd] = useState<NonVitalFactType | NonVitalEventType>()

  const conclusionList =
    conclusionCategory === 'otherEvent'
      ? getConclusionList('otherEvent', conclusionTypesToHide)
      : getConclusionList('otherFact', conclusionTypesToHide)

  const openAddNewConclusionOverlay = (type: NonVitalEventType | NonVitalFactType, e: UIEvent): void => {
    setConclusionTypeToAdd(type)
    trackEvent({ event_name: `open_add_new_${type}` })
    conclusionOverlay.handleClick(e)
  }

  if (!person) return null

  return (
    <>
      {(menuOverlay.isOpen || menuOverlay.transitioning) && (
        <MenuOverlay {...menuOverlay} data-testid="add-new-conclusion-overlay" {...menuOverlayProps}>
          {conclusionList.map((conclusionType) => {
            const conclusionDisplayName = getConclusionDisplayLabel(t, conclusionType)
            const singleValued = !CONCLUSION_PROPERTIES_MAP[conclusionType].multiValued
            const disabled =
              singleValued &&
              person.otherConclusions?.some((conclusion) => {
                return conclusion.type === conclusionType
              })
            return (
              <ListItem
                key={conclusionType}
                disabled={disabled || isTypeDisabled(conclusionType, conclusionTypesToDisable)}
                aria-label={t('conclusion.add.aria-label', { conclusion: conclusionDisplayName })}
                primaryText={conclusionDisplayName}
                onClick={(e: UIEvent) => openAddNewConclusionOverlay(conclusionType, e)}
                data-testid={conclusionType}
              />
            )
          })}
        </MenuOverlay>
      )}
      {conclusionTypeToAdd && (conclusionOverlay.isOpen || conclusionOverlay.transitioning) && (
        <Suspense fallback="">
          <ConclusionDialog overlay={conclusionOverlay} type={conclusionTypeToAdd} person={person} mode="add" />
        </Suspense>
      )}
    </>
  )
}
