import React, { useEffect, useState } from 'react'
import { Separator, H3, Grid } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { normalizePersonObj } from '@fs/zion-person-service'

import Person from '../Person/Person'

export default function FamilyMembers({ displayPerson, personObj }) {
  const [t] = useTranslation()
  const [spouseFamily, setSpouseFamily] = useState()
  const [parentFamily, setParentFamily] = useState()

  const focusPersonId = displayPerson.id

  useEffect(() => {
    let changedPerson = displayPerson || personObj
    if (changedPerson && !changedPerson.normalized) {
      changedPerson = normalizePersonObj(changedPerson)
    }
    const preferredSpouseFamily =
      changedPerson?.spouses?.find(({ preferred }) => preferred) || changedPerson?.spouses?.[0]
    setSpouseFamily(preferredSpouseFamily)
    const preferredParentFamily =
      changedPerson?.parents?.find(({ preferred }) => preferred) || changedPerson?.parents?.[0]
    setParentFamily(preferredParentFamily)
  }, [personObj, displayPerson])

  const { parent1: spouse1, parent2: spouse2, children } = spouseFamily || {}
  const { parent1, parent2, children: siblings } = parentFamily || {}

  const hasParents = parent1 || parent2
  const hasSpouse = spouse1 || spouse2

  return (
    <div>
      {hasSpouse && (
        <>
          <H3 size="H6">{t('person.person-sheet.spouse')}</H3>
          <Separator size="xxs" />
          <Person
            openPersonCard
            componentSize="sm"
            avatarSize="smaller"
            personObj={focusPersonId === spouse1?.id ? spouse2 : spouse1}
            noBoldName
          />
          <Separator size="sm" />
        </>
      )}
      {children?.length > 0 && (
        <>
          <H3 size="H6">{t('person.person-sheet.children')}</H3>
          <Separator size="xxs" />
          <Grid gutters="nano">
            {children.map((child) => {
              const childObj = child.child || child
              return (
                <Person
                  openPersonOverlay
                  key={childObj.id}
                  componentSize="sm"
                  avatarSize="smaller"
                  personObj={childObj}
                  noBoldName
                />
              )
            })}
            <Separator size="sm" />
          </Grid>
        </>
      )}
      {hasParents && (
        <>
          <H3 size="H6">{t('person.person-sheet.parents')}</H3>
          <Separator size="xxs" />
          <Grid gutters="nano">
            <Person openPersonOverlay componentSize="sm" avatarSize="smaller" personObj={parent1} noBoldName />
            <Person openPersonOverlay componentSize="sm" avatarSize="smaller" personObj={parent2} noBoldName />
          </Grid>
          <Separator size="sm" />
        </>
      )}
      {siblings?.length > 0 && (
        <>
          <H3 size="H6">{t('person.person-sheet.siblings')}</H3>
          <Separator size="xxs" />
          <Grid gutters="nano">
            {siblings.map((child) => {
              const childObj = child.child || child
              return (
                <Person
                  openPersonOverlay
                  key={childObj.id}
                  componentSize="sm"
                  avatarSize="smaller"
                  personObj={childObj}
                  noBoldName
                />
              )
            })}
          </Grid>
        </>
      )}
    </div>
  )
}
