import React from 'react'
import type { Person, ConclusionType } from '@fs/zion-tree-types'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import ConclusionDialog from './ConclusionDialog'

type AddConclusionDialogProps = {
  /** Overlay state object from useOverlay(). */
  overlay: UseOverlayReturnOptions

  /** The type of conclusion to add. */
  conclusionType: Exclude<ConclusionType, 'LIVED_TOGETHER' | 'COMMON_LAW_MARRIAGE' | 'DIVORCE' | 'ANNULMENT'>

  /** The person the conclusion will be added to. */
  person: Person

  /** Minimum height of dialog */
  minHeight?: number

  /** Maximum height of dialog */
  maxHeight?: number
}

export default function AddConclusionDialog({
  overlay,
  conclusionType,
  person,
  minHeight,
  maxHeight,
}: AddConclusionDialogProps): JSX.Element {
  return (
    <ConclusionDialog
      type={conclusionType}
      overlay={overlay}
      person={person}
      mode="add"
      minHeight={minHeight}
      maxHeight={maxHeight}
    />
  )
}
